'use strict';

/**
 *
 * @constructor
 * @ngInject
 */
function AlertsService($log, $timeout) {
  var alerts = {};

  function getAlertsFor(page) {
    var pageAlerts = alerts[page];
    if (!pageAlerts) {
      pageAlerts = [];
      alerts[page] = pageAlerts;
    }
    $log.debug('getting alerts for page ', page, pageAlerts);
    return pageAlerts;
  }

  function removeAlertFrom(page, index) {
    var pageAlerts = getAlertsFor(page);
    $log.debug('deleting alert on ', page, 'index', index);
    if (pageAlerts.length > index) {
      pageAlerts.splice(index, 1);
    }
  }

  function addAlertTo(page, alert) {
    var pageAlerts = getAlertsFor(page);
    $log.debug('adding alert ', page, alert);
    pageAlerts.push(alert);

    $timeout(function alertTimeout() {
      var index = pageAlerts.indexOf(alert);
      $log.debug('alert timeout for index', index);
      if (~index) {
        removeAlertFrom(page, index);
      }
    }, 5000);

  }

  return {
    getAlertsFor: getAlertsFor,
    addAlertTo: addAlertTo,
    removeAlertFrom: removeAlertFrom
  };
}

/**
 *
 * @constructor
 * @ngInject
 */
function AlertsFactory($log, $state, alertsService) {
  return function(alert) {
    $log.debug('ALERT ', $state, alert);
    alertsService.addAlertTo($state.current.name, alert);
  }
}


/**
 *
 * @ngInject
 */
function AlertsCtrl($scope, $state, alertsService) {

  var pageName = $state.current.name;
  $scope.alerts = alertsService.getAlertsFor(pageName);

  function remove(index) {
    alertsService.removeAlertFrom(pageName, index);
  }

  $scope.remove = remove;
}

/**
 *
 * @constructor
 * @ngInject
 */
function AlertsDirective() {
  return {
    restrict: 'EA',
    controllerAs: 'alertsCtrl',
    controller: 'AlertsCtrl',
    templateUrl: 'components/alerts/alerts.tpl.html',
    scope: {
    }
  };
}

angular.module('myApp')
  .factory('alertsService', AlertsService)
  .factory('alert', AlertsFactory)
  .controller('AlertsCtrl', AlertsCtrl)
  .directive('alerts', AlertsDirective);
